// CORREGIDO: verificar que el solicitante es dueño de estos datos
app.get('/api/users/:id', authMiddleware, (req, res) => {
  if (req.user.id !== req.params.id) return res.status(403).json({ error: 'Prohibido' });
  const user = db.findUser(req.params.id);
  res.json(user);
});
